// Function to get reading materials by subtopic name (case-insensitive)
function getReadingMaterials(subtopic) {
  // Check if subtopic is undefined, null, or empty
  if (!subtopic || typeof subtopic !== 'string') {
    return { readingMaterial1: null, readingMaterial2: null };
  }

  // Normalize subtopic to lowercase and trim whitespace
  const key = subtopic.trim().toLowerCase();

  // Retrieve materials or return default if subtopic not found
  const materials = readingMaterials[key] || {
    readingMaterial1: null,
    readingMaterial2: null
  };

  return materials;
}

// Get subtopic from input (from n8n input JSON)
const subtopicInput = $input.first().json.body.subtopic;

// Get reading materials for the subtopic
const result = getReadingMaterials(subtopicInput);

// Return the result in the expected format
return [
  {
    json: {
      subtopic: subtopicInput || null, // Handle case where subtopicInput is undefined
      readingMaterial1: result.readingMaterial1,
      readingMaterial2: result.readingMaterial2
    }
  }
];
